const ParseError = error{
    InvalidSyntax,
    UnexpectedToken,
    UnterminatedString,
};

const FileError = error{
    FileNotFound,
    PermissionDenied,
    EndOfStream,
};

const ConfigError = ParseError || FileError || error{
    MissingRequiredField,
    InvalidValue,
};

fn parseConfig(allocator: std.mem.Allocator, reader: anytype) ConfigError!Config {
    var buffer = try allocator.alloc(u8, 4096);
    errdefer allocator.free(buffer);

    const bytes_read = try reader.read(buffer);
    if (bytes_read == 0) return error.EndOfStream;

    return parseBuffer(buffer[0..bytes_read]);
}
